template.css:
/* Hero CTA Section - Full Width */
.hero-cta {
  background: var(--card-bg, linear-gradient(135deg, #6d28d9 0%, #3b82f6 100%));
  padding: var(--card-padding, 80px) 24px;
  text-align: center;
  position: relative;
  overflow: hidden;
  width: 100%;
}
.hero-cta::before {
  content: '';
  position: absolute;
  inset: 0;
  background: radial-gradient(ellipse at top, rgba(255,255,255,0.08) 0%, transparent 70%);
  pointer-events: none;
}
.hero-inner {
  max-width: 720px;
  margin: 0 auto;
  position: relative;
  z-index: 1;
}
.hero-eyebrow {
  font-size: var(--subtitle-font-size, 13px);
  font-weight: var(--subtitle-font-weight, 600);
  color: rgba(255,255,255,0.75);
  text-transform: uppercase;
  letter-spacing: 2px;
  margin: 0 0 16px;
}
.hero-title {
  font-size: clamp(32px, 5vw, var(--title-font-size, 48px));
  font-weight: var(--title-font-weight, 800);
  color: var(--title-color, #ffffff);
  line-height: 1.15;
  letter-spacing: -0.5px;
  margin: 0 0 20px;
}
.hero-desc {
  font-size: clamp(15px, 2vw, var(--description-font-size, 18px));
  color: var(--description-color, rgba(255,255,255,0.85));
  line-height: 1.7;
  margin: 0 0 40px;
}
.hero-actions {
  display: flex;
  gap: 16px;
  justify-content: center;
  flex-wrap: wrap;
  margin-bottom: 48px;
}
.hero-btn-primary {
  display: inline-block;
  padding: 14px 32px;
  background: #ffffff;
  color: #6d28d9;
  font-size: var(--button-font-size, 16px);
  font-weight: var(--button-font-weight, 700);
  border-radius: 50px;
  text-decoration: none;
  transition: all 0.25s ease;
  box-shadow: 0 4px 14px rgba(0,0,0,0.15);
}
.hero-btn-primary:hover {
  background: #f3f4f6;
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(0,0,0,0.2);
}
.hero-btn-secondary {
  display: inline-block;
  padding: 14px 32px;
  background: rgba(255,255,255,0.12);
  color: #ffffff;
  font-size: 16px;
  font-weight: 600;
  border-radius: 50px;
  text-decoration: none;
  border: 1px solid rgba(255,255,255,0.3);
  transition: all 0.25s ease;
  backdrop-filter: blur(4px);
}
.hero-btn-secondary:hover {
  background: rgba(255,255,255,0.22);
  transform: translateY(-2px);
}
.hero-stats {
  display: flex;
  gap: 40px;
  justify-content: center;
  flex-wrap: wrap;
}
.hero-stat {
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.stat-num {
  font-size: 28px;
  font-weight: 800;
  color: #ffffff;
}
.stat-label {
  font-size: 13px;
  color: rgba(255,255,255,0.65);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

/* Dark mode override */
[data-theme="dark"] .hero-cta {
  background: linear-gradient(135deg, #4c1d95 0%, #1e3a8a 100%);
}

/* RTL */
[dir="rtl"] .hero-actions { flex-direction: row-reverse; }

/* Responsive */
@media (max-width: 599px) {
  .hero-cta { padding: 60px 16px; }
  .hero-stats { gap: 24px; }
  .hero-btn-primary, .hero-btn-secondary { width: 100%; text-align: center; }
}
